54	impl SerializerRegistry for MockSerializerRegistry {
55	    fn serialize_logical_plan(
56	        &self,
57	        node: &dyn UserDefinedLogicalNode,
58	    ) -> Result<Vec<u8>> {
59	        if node.name() == "MockUserDefinedLogicalPlan" {
60	            let node = node
61	                .as_any()
62	                .downcast_ref::<MockUserDefinedLogicalPlan>()
63	                .unwrap();
64	            node.serialize()
65	        } else {
66	            unreachable!()
67	        }
68	    }
69	
70	    fn deserialize_logical_plan(
71	        &self,
72	        name: &str,
73	        bytes: &[u8],
74	    ) -> Result<Arc<dyn UserDefinedLogicalNode>> {
75	        if name == "MockUserDefinedLogicalPlan" {
76	            MockUserDefinedLogicalPlan::deserialize(bytes)
77	        } else {
78	            unreachable!()
79	        }
80	    }
81	}
