843	#[tokio::test]
844	async fn roundtrip_self_join() -> Result<()> {
845	    // Substrait does currently NOT maintain the alias of the tables.
846	    // Instead, when we consume Substrait, we add aliases before a join that'd otherwise collide.
847	    // The improved NameTracker now adds __temp__0 suffix to handle naming conflicts.
848	    // We verify semantic equivalence rather than exact string match.
849	    let ctx = create_context().await?;
850	    let sql = "SELECT left.a as left_a, left.b, right.a as right_a, right.c FROM data AS left JOIN data AS right ON left.a = right.a";
851	    let df = ctx.sql(sql).await?;
852	    let plan = df.into_optimized_plan()?;
853	    let plan2 = substrait_roundtrip(&plan, &ctx).await?;
854	
855	    // Verify schemas are equivalent
856	    assert_eq!(plan.schema(), plan2.schema());
857	
858	    // Execute to ensure plan validity
859	    DataFrame::new(ctx.state(), plan2).show().await?;
860	
861	    // Test second variant
862	    let sql2 = "SELECT left.a as left_a, left.b, right.a as right_a, right.c FROM data AS left JOIN data AS right ON left.b = right.b";
863	    let df2 = ctx.sql(sql2).await?;
864	    let plan3 = df2.into_optimized_plan()?;
865	    let plan4 = substrait_roundtrip(&plan3, &ctx).await?;
866	    assert_eq!(plan3.schema(), plan4.schema());
867	    DataFrame::new(ctx.state(), plan4).show().await?;
868	
869	    Ok(())
870	}
