1557	    let plan = df.into_optimized_plan()?;
1558	    let plan2 = substrait_roundtrip(&plan, &ctx).await?;
1559	
1560	    // Verify schemas are equivalent
1561	    assert_eq!(plan.schema(), plan2.schema());
1562	
