1757	fn check_post_join_filters(rel: &Rel) -> Result<()> {
1758	    // search for target_rel and field value in proto
1759	    match &rel.rel_type {
1760	        Some(RelType::Join(join)) => {
1761	            // check if join filter is None
1762	            if join.post_join_filter.is_some() {
1763	                plan_err!(
1764	                    "DataFusion generated Substrait plan cannot have post_join_filter in JoinRel"
1765	                )
1766	            } else {
1767	                // recursively check JoinRels
1768	                match check_post_join_filters(join.left.as_ref().unwrap().as_ref()) {
1769	                    Err(e) => Err(e),
1770	                    Ok(_) => {
1771	                        check_post_join_filters(join.right.as_ref().unwrap().as_ref())
1772	                    }
1773	                }
1774	            }
1775	        }
1776	        Some(RelType::Project(p)) => {
1777	            check_post_join_filters(p.input.as_ref().unwrap().as_ref())
1778	        }
1779	        Some(RelType::Filter(filter)) => {
1780	            check_post_join_filters(filter.input.as_ref().unwrap().as_ref())
1781	        }
1782	        Some(RelType::Fetch(fetch)) => {
1783	            check_post_join_filters(fetch.input.as_ref().unwrap().as_ref())
1784	        }
1785	        Some(RelType::Sort(sort)) => {
1786	            check_post_join_filters(sort.input.as_ref().unwrap().as_ref())
1787	        }
1788	        Some(RelType::Aggregate(agg)) => {
1789	            check_post_join_filters(agg.input.as_ref().unwrap().as_ref())
1790	        }
1791	        Some(RelType::Set(set)) => {
1792	            for input in &set.inputs {
1793	                match check_post_join_filters(input) {
1794	                    Err(e) => return Err(e),
1795	                    Ok(_) => continue,
1796	                }
1797	            }
1798	            Ok(())
1799	        }
1800	        Some(RelType::ExtensionSingle(ext)) => {
1801	            check_post_join_filters(ext.input.as_ref().unwrap().as_ref())
1802	        }
1803	        Some(RelType::ExtensionMulti(ext)) => {
1804	            for input in &ext.inputs {
1805	                match check_post_join_filters(input) {
1806	                    Err(e) => return Err(e),
1807	                    Ok(_) => continue,
1808	                }
1809	            }
1810	            Ok(())
1811	        }
1812	        Some(RelType::ExtensionLeaf(_)) | Some(RelType::Read(_)) => Ok(()),
1813	        _ => not_impl_err!(
1814	            "Unsupported Reltype: {:?} in post join filter check",
1815	            rel.rel_type
1816	        ),
1817	    }
1818	}
