    @r"
    Projection: data.a + Int64(1) AS sum_a, data.a + Int64(1) AS data.a + Int64(1)__temp__0 AS sum_a_2
      Projection: data.a + Int64(1)
        TableScan: data projection=[a]
    "
        );
    Ok(())
}

