283	                RelType::Window(w) => {
284	                    self.apply(w.input.as_ref().map(|b| b.as_ref()))?;
285	                    for wf in w.window_functions.iter() {
286	                        for arg in wf.arguments.iter() {
287	                            self.collect_schemas_from_arg(arg)?;
288	                        }
289	                    }
290	                    for expr in w.partition_expressions.iter() {
291	                        self.collect_schemas_from_expr(expr)?;
292	                    }
293	                    for sort_field in w.sorts.iter() {
294	                        if let Some(expr) = sort_field.expr.as_ref() {
295	                            self.collect_schemas_from_expr(expr)?;
296	                        }
297	                    }
298	                }
299	                RelType::Exchange(e) => {
300	                    self.apply(e.input.as_ref().map(|b| b.as_ref()))?;
301	                    let exchange_kind = e.exchange_kind.as_ref().ok_or(
302	                        substrait_datafusion_err!("Exchange must set exchange_kind"),
303	                    )?;
304	                    match exchange_kind {
305	                        ExchangeKind::ScatterByFields(_) => {}
306	                        ExchangeKind::SingleTarget(st) => {
307	                            if let Some(expr) = st.expression.as_ref() {
308	                                self.collect_schemas_from_expr(expr)?
309	                            }
310	                        }
311	                        ExchangeKind::MultiTarget(mt) => {
312	                            if let Some(expr) = mt.expression.as_ref() {
313	                                self.collect_schemas_from_expr(expr)?
314	                            }
315	                        }
316	                        ExchangeKind::RoundRobin(_) => {}
317	                        ExchangeKind::Broadcast(_) => {}
318	                    }
319	                }
320	                RelType::Expand(e) => {
321	                    self.apply(e.input.as_ref().map(|b| b.as_ref()))?;
322	                    for expand_field in e.fields.iter() {
323	                        let expand_type = expand_field.field_type.as_ref().ok_or(
324	                            substrait_datafusion_err!("ExpandField must set field_type"),
325	                        )?;
326	                        match expand_type {
327	                            FieldType::SwitchingField(sf) => {
328	                                for expr in sf.duplicates.iter() {
329	                                    self.collect_schemas_from_expr(expr)?;
330	                                }
331	                            }
332	                            FieldType::ConsistentField(expr) => {
333	                                self.collect_schemas_from_expr(expr)?
334	                            }
335	                        }
336	                    }
337	                }
338	                _ => todo!(),
339	            }
340	            Ok(())
341	        }
342	
343	        fn apply(&mut self, input: Option<&Rel>) -> Result<()> {
344	            match input {
345	                None => Ok(()),
346	                Some(rel) => self.collect_schemas_from_rel(rel),
347	            }
348	        }
349	
350	        fn collect_schemas_from_expr(&mut self, e: &Expression) -> Result<()> {
351	            let rex_type = e.rex_type.as_ref().ok_or(substrait_datafusion_err!(
352	                "rex_type must be set on Expression"
353	            ))?;
354	            match rex_type {
355	                RexType::Literal(_) => {}
356	                RexType::Selection(_) => {}
357	                RexType::ScalarFunction(sf) => {
358	                    for arg in sf.arguments.iter() {
359	                        self.collect_schemas_from_arg(arg)?
360	                    }
361	                }
362	                RexType::WindowFunction(wf) => {
363	                    for arg in wf.arguments.iter() {
364	                        self.collect_schemas_from_arg(arg)?
365	                    }
366	                    for sort_field in wf.sorts.iter() {
367	                        if let Some(expr) = sort_field.expr.as_ref() {
368	                            self.collect_schemas_from_expr(expr)?
369	                        }
370	                    }
371	                    for expr in wf.partitions.iter() {
372	                        self.collect_schemas_from_expr(expr)?
373	                    }
374	                }
375	                RexType::IfThen(it) => {
376	                    for if_clause in it.ifs.iter() {
377	                        if let Some(expr) = if_clause.r#if.as_ref() {
378	                            self.collect_schemas_from_expr(expr)?;
379	                        };
380	                        if let Some(expr) = if_clause.then.as_ref() {
381	                            self.collect_schemas_from_expr(expr)?;
382	                        };
383	                    }
384	                    if let Some(expr) = it.r#else.as_ref() {
385	                        self.collect_schemas_from_expr(expr)?;
386	                    };
387	                }
388	                RexType::SwitchExpression(se) => {
389	                    if let Some(expr) = se.r#match.as_ref() {
390	                        self.collect_schemas_from_expr(expr)?
391	                    }
392	                    for if_value in se.ifs.iter() {
393	                        if let Some(expr) = if_value.then.as_ref() {
394	                            self.collect_schemas_from_expr(expr)?
395	                        }
396	                    }
397	                    if let Some(expr) = se.r#else.as_ref() {
398	                        self.collect_schemas_from_expr(expr)?
399	                    }
400	                }
401	                RexType::SingularOrList(sol) => {
402	                    if let Some(expr) = sol.value.as_ref() {
403	                        self.collect_schemas_from_expr(expr)?
404	                    }
405	                    for expr in sol.options.iter() {
406	                        self.collect_schemas_from_expr(expr)?
407	                    }
408	                }
409	                RexType::MultiOrList(mol) => {
410	                    for expr in mol.value.iter() {
411	                        self.collect_schemas_from_expr(expr)?
412	                    }
413	                    for record in mol.options.iter() {
414	                        for expr in record.fields.iter() {
415	                            self.collect_schemas_from_expr(expr)?
416	                        }
417	                    }
418	                }
419	                RexType::Cast(c) => {
420	                    if let Some(expr) = c.input.as_ref() {
421	                        self.collect_schemas_from_expr(expr)?
422	                    }
423	                }
424	                RexType::Subquery(subquery) => {
425	                    let subquery_type = subquery
426	                        .subquery_type
427	                        .as_ref()
428	                        .ok_or(substrait_datafusion_err!("subquery_type must be set"))?;
429	                    match subquery_type {
430	                        SubqueryType::Scalar(s) => {
431	                            if let Some(rel) = s.input.as_ref() {
432	                                self.collect_schemas_from_rel(rel)?;
433	                            }
434	                        }
435	                        SubqueryType::InPredicate(ip) => {
436	                            for expr in ip.needles.iter() {
437	                                self.collect_schemas_from_expr(expr)?;
438	                            }
439	                            if let Some(rel) = ip.haystack.as_ref() {
440	                                self.collect_schemas_from_rel(rel)?;
441	                            }
442	                        }
443	                        SubqueryType::SetPredicate(sp) => {
444	                            if let Some(rel) = sp.tuples.as_ref() {
445	                                self.collect_schemas_from_rel(rel)?;
446	                            }
447	                        }
448	                        SubqueryType::SetComparison(sc) => {
449	                            if let Some(expr) = sc.left.as_ref() {
450	                                self.collect_schemas_from_expr(expr)?;
451	                            }
452	                            if let Some(rel) = sc.right.as_ref() {
453	                                self.collect_schemas_from_rel(rel)?;
454	                            }
455	                        }
456	                    }
457	                }
458	                RexType::Nested(n) => {
459	                    let nested_type = n.nested_type.as_ref().ok_or(
460	                        substrait_datafusion_err!("Nested must set nested_type"),
461	                    )?;
462	                    match nested_type {
463	                        NestedType::Struct(s) => {
464	                            for expr in s.fields.iter() {
465	                                self.collect_schemas_from_expr(expr)?;
466	                            }
467	                        }
468	                        NestedType::List(l) => {
469	                            for expr in l.values.iter() {
470	                                self.collect_schemas_from_expr(expr)?;
471	                            }
472	                        }
473	                        NestedType::Map(m) => {
474	                            for key_value in m.key_values.iter() {
475	                                if let Some(expr) = key_value.key.as_ref() {
476	                                    self.collect_schemas_from_expr(expr)?;
477	                                }
478	                                if let Some(expr) = key_value.value.as_ref() {
479	                                    self.collect_schemas_from_expr(expr)?;
480	                                }
481	                            }
482	                        }
483	                    }
484	                }
485	                RexType::DynamicParameter(_) => {}
486	                // Enum is deprecated
487	                #[expect(deprecated)]
488	                RexType::Enum(_) => {}
489	                RexType::Lambda(_) | RexType::LambdaInvocation(_) => {}
490	            }
491	            Ok(())
492	        }
493	
494	        fn collect_schemas_from_arg(&mut self, fa: &FunctionArgument) -> Result<()> {
495	            let arg_type = fa.arg_type.as_ref().ok_or(substrait_datafusion_err!(
496	                "FunctionArgument must set arg_type"
497	            ))?;
498	            match arg_type {
499	                ArgType::Enum(_) => {}
500	                ArgType::Type(_) => {}
501	                ArgType::Value(expr) => self.collect_schemas_from_expr(expr)?,
502	            }
503	            Ok(())
504	        }
505	    }
506	}
