            )?
            .build()
        }
        None => {
            let on: Vec<String> = vec![];
            left.join_detailed(
                right.build()?,
                join_type,
                (on.clone(), on),
                None,
                NullEquality::NullEqualsNothing,
            )?
            .build()
        }
    }
}

fn split_eq_and_noneq_join_predicate_with_nulls_equality(
    filter: &Expr,
) -> (Vec<(Column, Column)>, bool, Option<Expr>) {
    let exprs = split_conjunction(filter);

    let mut eq_join_keys: Vec<(Column, Column)> = vec![];
    let mut distinct_join_keys: Vec<(Column, Column)> = vec![];
    let mut accum_filters: Vec<Expr> = vec![];

    for expr in exprs {
        #[expect(clippy::collapsible_match)]
        match expr {
            Expr::BinaryExpr(binary_expr) => match binary_expr {
                BinaryExpr {
                    left,
                    op: Operator::Eq,
                    right,
                } => match (left.as_ref(), right.as_ref()) {
                    (Expr::Column(l), Expr::Column(r)) => {
                        eq_join_keys.push((l.clone(), r.clone()));
                    }
                    _ => accum_filters.push(expr.clone()),
                },
                BinaryExpr {
                    left,
                    op: Operator::IsNotDistinctFrom,
                    right,
                } => match (left.as_ref(), right.as_ref()) {
                    (Expr::Column(l), Expr::Column(r)) => {
                        distinct_join_keys.push((l.clone(), r.clone()));
                    }
                    _ => accum_filters.push(expr.clone()),
                },
                _ => accum_filters.push(expr.clone()),
            },
            _ => accum_filters.push(expr.clone()),
        }
    }

    // Determine null semantics for the join keys.
    // DataFusion's Join API only supports a single NullEquality for all join keys.
    // If all keys have the same null semantics, use that.
    // If keys have mixed null semantics (some Eq, some IsNotDistinctFrom),
    // we put Eq keys as join keys with NullEqualsNothing and move
    // IsNotDistinctFrom keys to the join filter as explicit conditions.
    let (join_keys, nulls_equal_nulls) = match (!eq_join_keys.is_empty(), !distinct_join_keys.is_empty()) {
        (true, false) => (eq_join_keys, false),
        (false, true) => (distinct_join_keys, true),
        (true, true) => {
            // Mixed semantics: keep Eq keys as join keys, move IsNotDistinctFrom to filter
            for (l, r) in &distinct_join_keys {
                accum_filters.push(Expr::BinaryExpr(BinaryExpr::new(
                    Box::new(Expr::Column(l.clone())),
                    Operator::IsNotDistinctFrom,
                    Box::new(Expr::Column(r.clone())),
                )));
            }
            (eq_join_keys, false)
        }
        (false, false) => (vec![], false),
    };

    let join_filter = accum_filters.into_iter().reduce(Expr::and);
    (join_keys, nulls_equal_nulls, join_filter)
}

fn from_substrait_jointype(join_type: i32) -> datafusion::common::Result<JoinType> {
    if let Ok(substrait_join_type) = join_rel::JoinType::try_from(join_type) {
        match substrait_join_type {
            join_rel::JoinType::Inner => Ok(JoinType::Inner),
            join_rel::JoinType::Left => Ok(JoinType::Left),
            join_rel::JoinType::Right => Ok(JoinType::Right),
            join_rel::JoinType::Outer => Ok(JoinType::Full),
            join_rel::JoinType::LeftAnti => Ok(JoinType::LeftAnti),
            join_rel::JoinType::LeftSemi => Ok(JoinType::LeftSemi),
            join_rel::JoinType::LeftMark => Ok(JoinType::LeftMark),
            join_rel::JoinType::RightMark => Ok(JoinType::RightMark),
            join_rel::JoinType::RightAnti => Ok(JoinType::RightAnti),
            join_rel::JoinType::RightSemi => Ok(JoinType::RightSemi),
            _ => plan_err!("unsupported join type {substrait_join_type:?}"),
        }
    } else {
        plan_err!("invalid join type variant {join_type}")
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use datafusion::common::Column;
    use datafusion::logical_expr::{binary_expr, col, Operator};

    fn column(name: &str, relation: Option<&str>) -> Column {
        Column {
            relation: relation.map(|s| s.into()),
            name: name.into(),
        }
    }

    #[test]
    fn test_all_eq_keys() {
        // All keys use Eq -> nulls_equal_nulls should be false
        let expr = binary_expr(
            binary_expr(
                Expr::Column(column("id", Some("t1"))),
                Operator::Eq,
                Expr::Column(column("id", Some("t2"))),
            ),
            Operator::And,
            binary_expr(
                Expr::Column(column("val", Some("t1"))),
                Operator::Eq,
                Expr::Column(column("val", Some("t2"))),
            ),
        );
        let (keys, nulls_equal_nulls, filter) =
            split_eq_and_noneq_join_predicate_with_nulls_equality(&expr);
        assert_eq!(keys.len(), 2);
        assert!(!nulls_equal_nulls);
        assert!(filter.is_none());
    }

    #[test]
    fn test_all_distinct_keys() {
        // All keys use IsNotDistinctFrom -> nulls_equal_nulls should be true
        let expr = binary_expr(
            binary_expr(
                Expr::Column(column("id", Some("t1"))),
                Operator::IsNotDistinctFrom,
                Expr::Column(column("id", Some("t2"))),
            ),
            Operator::And,
            binary_expr(
                Expr::Column(column("val", Some("t1"))),
                Operator::IsNotDistinctFrom,
                Expr::Column(column("val", Some("t2"))),
            ),
        );
        let (keys, nulls_equal_nulls, filter) =
            split_eq_and_noneq_join_predicate_with_nulls_equality(&expr);
        assert_eq!(keys.len(), 2);
        assert!(nulls_equal_nulls);
        assert!(filter.is_none());
    }

    #[test]
    fn test_mixed_keys() {
        // Mixed: one Eq key, one IsNotDistinctFrom key
        // The Eq key should be kept as join key with NullEqualsNothing,
        // and the IsNotDistinctFrom key should be moved to the filter
        let expr = Expr::BinaryExpr(BinaryExpr::new(
            Box::new(Expr::BinaryExpr(BinaryExpr::new(
                Box::new(Expr::Column(column("id", Some("t1")))),
                Operator::Eq,
                Box::new(Expr::Column(column("id", Some("t2")))),
            ))),
            Operator::And,
            Box::new(Expr::BinaryExpr(BinaryExpr::new(
                Box::new(Expr::Column(column("val", Some("t1")))),
                Operator::IsNotDistinctFrom,
                Box::new(Expr::Column(column("val", Some("t2")))),
            ))),
        ));
        let (keys, nulls_equal_nulls, filter) =
            split_eq_and_noneq_join_predicate_with_nulls_equality(&expr);

        // Only the Eq key should be in the join keys
        assert_eq!(keys.len(), 1);
        assert_eq!(keys[0].0.name, "id");
        assert_eq!(keys[0].1.name, "id");

        // nulls_equal_nulls should be false
        assert!(!nulls_equal_nulls);

        // The IsNotDistinctFrom key should be in the filter
        assert!(filter.is_some());
        let filter_expr = filter.unwrap();
        match &filter_expr {
            Expr::BinaryExpr(be) => {
                assert_eq!(be.op, Operator::IsNotDistinctFrom);
                if let Expr::Column(l) = be.left.as_ref() {
                    assert_eq!(l.name, "val");
                } else {
                    panic!("Expected left Column");
                }
                if let Expr::Column(r) = be.right.as_ref() {
                    assert_eq!(r.name, "val");
                } else {
                    panic!("Expected right Column");
                }
            }
            _ => panic!("Expected BinaryExpr in filter, got {filter_expr:?}"),
        }
    }

    #[test]
    fn test_non_column_expr() {
        // Non-column binary expressions should go to filter
        let expr = binary_expr(
            Expr::Column(column("id", Some("t1"))),
            Operator::Eq,
            Expr::Column(column("id", Some("t2"))),
        ).and(Expr::Literal(datafusion::scalar::ScalarValue::Boolean(Some(true))));
        let (keys, nulls_equal_nulls, filter) =
            split_eq_and_noneq_join_predicate_with_nulls_equality(&expr);
        assert_eq!(keys.len(), 1);
        assert!(!nulls_equal_nulls);
        assert!(filter.is_some());
    }
}

